package hw03.model.strategy;

import java.awt.Graphics;

import hw03.model.Ball;
import hw03.model.IUpdateStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author Christina
 * Ball expands and contracts
 */
public class ExpandingStrategy implements IUpdateStrategy {

	/**
	 * Boolean for whether should expand or not
	 */
	boolean expand = true;
	/**
	 * @param disp the dispatcher to communicate
	 * @param ball the ball class
	 */
	public void updateState(IDispatcher<Graphics> disp, Ball ball) {
		int radius = ball.getRadius();
		if (radius >= 60) {
			expand = false;
		} else if (radius <= 5) {
			expand = true;
		}
		if (expand) {
			radius += 2;
			if (radius >= 60) {
				radius = 60;
				expand = false;
			}
		} else {
			radius -= 2;
			if (radius <= 5) {
				radius = 5;
				expand = true;
			}
		}
		ball.setRadius(radius);
	}
}

package hw03.model.strategy;

import java.awt.Graphics;
import java.awt.Point;

import hw03.model.Ball;
import hw03.model.IUpdateStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * 
 * @author charlielockyer
 * A strategy in which a ball splits into two when it hits a wall
 */
public class ExplodingStrategy implements IUpdateStrategy{

	/**
	 * Updates the state like in all strategies
	 */
	public void updateState(IDispatcher<Graphics> disp, Ball ball) {
		boolean[] bounced = ball.hasBounced();
		if (bounced[0] || bounced[1]) {
			Point location = ball.getLocation();
			Point velocity = ball.getVelocity();
			Ball spawned = new Ball(new Point(location.x, location.y), new Point(-velocity.x, -velocity.y),
					ball.getColor(), ball.getRadius(), ball.getDimension(), new ExplodingStrategy());
			disp.addObserver(spawned);
			bounced[0] = false;
			bounced[1] = false;
		}
	}

}

package hw03.model.strategy;

import java.awt.Graphics;
import java.awt.Point;

import hw03.model.Ball;
import hw03.model.IUpdateStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author Christina
 * Strategy that implements gravity on the ball
 */
public class GravityStrategy implements IUpdateStrategy {


	/**
	 * @param disp the dispatcher to communicate
	 * @param ball the ball class
	 */
	public void updateState(IDispatcher<Graphics> disp, Ball ball) {
		Point velocity = ball.getVelocity();
		velocity.y += 1;
		ball.setVelocity(velocity);
	}

}

package hw03.model.strategy;

import java.awt.Point;
import java.util.Random;

import hw03.model.Ball;
import java.awt.Graphics;
import hw03.model.IUpdateStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author Christina
 * Strategy that randomly changes the velocity of the ball
 */
public class RandomWalkStrategy implements IUpdateStrategy {
	private final Random rand = new Random();


	/**
	 * @param disp the dispatcher to communicate
	 * @param ball the ball class
	 */
	public void updateState(IDispatcher<Graphics> disp, Ball ball) {
		Point velocity = ball.getVelocity();
		velocity.x += rand.nextBoolean() ? 1 : -1;
		velocity.y += rand.nextBoolean() ? 1 : -1;
		ball.setVelocity(velocity);
	}
}

package hw03.model.strategy;

import java.awt.Graphics;
import java.awt.Point;

import hw03.model.Ball;
import hw03.model.IUpdateStrategy;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author Christina
 * Strategy that reverse the ball every 10 ticks
 */
public class ReverseStrategy implements IUpdateStrategy {
	private int ticks = 0;

	/**
	 * @param disp the dispatcher to communicate
	 * @param ball the ball class
	 */
	public void updateState(IDispatcher<Graphics> disp, Ball ball) {
		ticks++;
		if (ticks > 10) {
			Point velocity = ball.getVelocity();
			velocity.x = -velocity.x;
			velocity.y = -velocity.y;
			ball.setVelocity(velocity);
			ticks = 0;
		}
	}

}

